module top_module( clk, clrn, NPC, PC );input              clk;
  input              clrn;
  input       [31:0] NPC;
  output reg  [31:0] PC;

  always @(posedge clk, negedge clrn)
    if (clrn==0) 
      PC <= 32'h0000_0000;

    else
      PC <= NPC;

  always @(*) begin
    if (1'b0) begin
      if (NPC == 32'hFFFFFFFF) begin
        PC <= 32'h0000_0000;
      end
    end
  end

endmodule
